-- Eval-tracking datasets: the second mode of dataset_rows.
--
-- Synthesis datasets (the original mode) are generated by submitting a prompt
-- list to the Claude Batch API; rows arrive asynchronously from the poller.
--
-- Eval datasets are manually-curated records of running our own fine-tuned
-- model on a test spec: you paste the spec (input), the model's raw output,
-- and then mark per-row meta after compiling/running the generated plugin:
--   {
--     plugin_name:  "RepairItem",
--     complexity:   "tiny|small|medium|large|xl",
--     compile:      true|false,
--     runtime:      true|false,
--     failure_type: "deprecated_api" | "missing_import" | null,
--     fix_applied:  "used Damageable",
--     notes:        "..."
--   }
--
-- Export can then filter on meta to produce a clean training JSONL for the
-- next fine-tune ("give me only the rows where both compile and runtime
-- passed"), closing the v1 → v2 dataset loop.

-- 1) `kind` discriminator on datasets. 'synthesis' preserves the existing
--    Claude-Batch behaviour; 'eval' is the new manual-entry mode.
alter table public.datasets
  add column kind text not null default 'synthesis'
  check (kind in ('synthesis','eval'));

-- 2) Per-row eval metadata. Free-form jsonb so we can iterate on which fields
--    to track without schema migrations every time.
alter table public.dataset_rows
  add column meta jsonb not null default '{}'::jsonb;

-- 3) GIN index over meta so filters like `meta->>'compile' = 'true'` and
--    `meta ? 'failure_type'` stay fast as the table grows.
create index dataset_rows_meta_gin on public.dataset_rows using gin (meta);

-- 4) Publish dataset_rows to Supabase Realtime so the UI re-fetches when a
--    row is inserted/updated. Synthesis mode already relied on polling the
--    parent `datasets` row to trigger a refresh, but manual eval entry needs
--    row-level updates to feel live.
alter publication supabase_realtime add table public.dataset_rows;
